), imported as (
  select 'usaha' as scope, r.diperbarui, r.dinonaktifkan
  from payload p
  cross join public.import_anomali_pusat_batch('usaha', coalesce(p.data -> 'usaha', '[]'::jsonb)) r

  union all

  select 'keluarga' as scope, r.diperbarui, r.dinonaktifkan
  from payload p
  cross join public.import_anomali_pusat_batch('keluarga', coalesce(p.data -> 'keluarga', '[]'::jsonb)) r
)
